INSERT INTO `problems` VALUES (5,4,4,1,'«В один ход» с ловушкой','mkt-trap-1','medium','','## Условие\n\nКакова масса одной молекулы кислорода $O_2$? Ответ выразите в граммах, округлив до сотых, умножив на $10^{-23}$ (или запишите в стандартном виде).\n','\n## Где ошибаются\nСмотрим в таблицу Менделеева, видим у кислорода массу $16$ и ее подставляем\n\n## Правильное решение\n\nКислород — газ **двухатомный**. Молярная масса газа:\n\n**M = 2 · 16 = 32 г/моль = 0,032 кг/моль**\n\nПрименяем базовую формулу:\n\n**m₀ = M / Nₐ = 0,032 кг/моль / (6,02 · 10²³ моль⁻¹) ≈ 5,32 · 10⁻²⁶ кг**\n\nПереводим в граммы:\n\n**5,32 · 10⁻²³ г**','**5,32 · 10⁻²³ г**','draft','2026-07-02 15:36:42','2026-07-02 15:36:42');
/*!40000 ALTER TABLE `problems` ENABLE KEYS */;
UNLOCK TABLES;

